pub struct InsertionValueConverter;

impl InsertionValueConverter {
    pub fn rate1(value: u8) -> f64 {
        DATA[value as usize][5]
    }

    pub fn eq_freq(value: u8) -> f64 {
        DATA[value as usize][9]
    }

    pub fn manual(value: u8) -> f64 {
        DATA[value.min(127) as usize][11]
    }
}
